class NumberedCanvas(canvas.Canvas):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self._saved_page_states = []
    def showPage(self):
        self._saved_page_states.append(dict(self.__dict__))
        self._startPage()
    def save(self):
        page_count = len(self._saved_page_states)
        for state in self._saved_page_states:
            self.__dict__.update(state)
            if self._pageNumber > 1:
                self.setFont('Helvetica', 9)
                self.setFillColor(colors.grey)
                self.drawString(2*cm, 1.2*cm, 'InfraSight - Great Zimbabwe University - rf-v1')
                self.drawRightString(A4[0]-2*cm, 1.2*cm, f'Page {self._pageNumber - 1}')
            canvas.Canvas.showPage(self)
        canvas.Canvas.save(self)

class DocTemplate(SimpleDocTemplate):
    def afterFlowable(self, flowable):
        if isinstance(flowable, Paragraph):
            text = flowable.getPlainText()
            style = flowable.style.name
            if style == 'MajorHeading':
                key = 'h1-%s' % text
                self.canv.bookmarkPage(key)
                self.notify('TOCEntry', (0, text, self.page, key))

def make_styles():
    styles = getSampleStyleSheet()
    styles.add(ParagraphStyle(name='CoverTitle', parent=styles['Title'], fontName='Helvetica-Bold', fontSize=24, leading=32, textColor=GZU_GREEN, alignment=TA_CENTER, spaceAfter=18))
    styles.add(ParagraphStyle(name='CoverSub', parent=styles['Normal'], fontSize=14, leading=20, alignment=TA_CENTER, spaceAfter=10))
    styles.add(ParagraphStyle(name='MajorHeading', parent=styles['Heading1'], fontName='Helvetica-Bold', fontSize=18, leading=24, textColor=GZU_GREEN, spaceAfter=14, spaceBefore=6))
    styles.add(ParagraphStyle(name='SectionHeading', parent=styles['Heading2'], fontName='Helvetica-Bold', fontSize=14, leading=19, textColor=GZU_GREEN, spaceAfter=8, spaceBefore=10))
    styles.add(ParagraphStyle(name='Body11', parent=styles['BodyText'], fontName='Helvetica', fontSize=11, leading=15.4, spaceAfter=8))
    styles.add(ParagraphStyle(name='Bullet11', parent=styles['BodyText'], fontName='Helvetica', fontSize=11, leading=15.4, leftIndent=16, bulletIndent=6, spaceAfter=4))
    styles.add(ParagraphStyle(name='CodeBlock', parent=styles['Code'], fontName='Courier', fontSize=9, leading=12, backColor=colors.HexColor('#f3f4f6'), borderColor=GZU_GREEN, borderWidth=0.5, borderPadding=6, spaceAfter=8))
    return styles

def table_flowable(header, rows, widths=None):
    data = [[Paragraph(f'<b>{c}</b>', STYLES['Body11']) for c in header.split(',')]]
    for row in rows:
        data.append([Paragraph(str(c), STYLES['Body11']) for c in row])
    tbl = Table(data, repeatRows=1, colWidths=widths)
    tbl.setStyle(TableStyle([
        ('BACKGROUND', (0,0), (-1,0), colors.HexColor('#e5e7eb')),
        ('TEXTCOLOR', (0,0), (-1,0), colors.black),
        ('GRID', (0,0), (-1,-1), 0.4, colors.HexColor('#d1d5db')),
        ('VALIGN', (0,0), (-1,-1), 'TOP'),
        ('FONTNAME', (0,0), (-1,0), 'Helvetica-Bold'),
        ('ROWBACKGROUNDS', (0,1), (-1,-1), [colors.white, colors.HexColor('#f9fafb')]),
        ('LEFTPADDING', (0,0), (-1,-1), 6),
        ('RIGHTPADDING', (0,0), (-1,-1), 6),
        ('TOPPADDING', (0,0), (-1,-1), 6),
        ('BOTTOMPADDING', (0,0), (-1,-1), 6),
    ]))
    return tbl

def build():
    story = []
    story.extend([
        Spacer(1, 5*cm),
        Paragraph('InfraSight', STYLES['CoverTitle']),
        Paragraph('ICT Fault Detection and Predictive Maintenance System', STYLES['CoverSub']),
        Spacer(1, 1.2*cm),
        Paragraph('<b>Institution:</b> Great Zimbabwe University', STYLES['CoverSub']),
        Paragraph('<b>Department:</b> Department of Information and Communication Technology', STYLES['CoverSub']),
        Paragraph('<b>Document type:</b> System Documentation, User Guide and Technical Manual', STYLES['CoverSub']),
        Paragraph('<b>Version:</b> 1.0', STYLES['CoverSub']),
        Paragraph('<b>Date:</b> May 2026', STYLES['CoverSub']),
        Paragraph('<b>Prepared by:</b> GZU Final Year Project', STYLES['CoverSub']),
        Spacer(1, 2*cm),
        Paragraph('<font color="#7f1d1d"><b>Confidential - Academic Use Only</b></font>', STYLES['CoverSub']),
        PageBreak(),
    ])
    toc = TableOfContents()
    toc.levelStyles = [ParagraphStyle(fontName='Helvetica', fontSize=11, name='TOCLevel1', leftIndent=0, firstLineIndent=0, spaceBefore=5, leading=14)]
    story.append(Paragraph('Table of Contents', STYLES['MajorHeading']))
    story.append(toc)
    story.append(PageBreak())
    for num, title, paras, subs, tables in sections:
        story.append(Paragraph(f'Section {num}: {title}', STYLES['MajorHeading']))
        for p in paras:
            story.append(Paragraph(p, STYLES['Body11']))
        for sub, items in subs:
            story.append(Paragraph(sub, STYLES['SectionHeading']))
            if len(items) == 1 and len(items[0]) > 130:
                story.append(Paragraph(items[0], STYLES['Body11']))
            else:
                for item in items:
                    story.append(Paragraph(item, STYLES['Bullet11'], bulletText='-'))
        for header, rows in tables:
            story.append(table_flowable(header, rows))
            story.append(Spacer(1, 8))
        story.append(PageBreak())
    return story

STYLES = make_styles()
doc = DocTemplate(str(OUTPUT), pagesize=A4, rightMargin=2*cm, leftMargin=2*cm, topMargin=2*cm, bottomMargin=2*cm, pageCompression=0)
doc.multiBuild(build(), canvasmaker=NumberedCanvas)
reader = PdfReader(str(OUTPUT))
print(f'PDF={OUTPUT}')
print(f'PAGES={len(reader.pages)}')
print(f'SIZE={OUTPUT.stat().st_size}')
